   162→    <script>
   163→        const subjectSelect = document.getElementById("subjectSelect");
   164→        const chapterSelect = document.getElementById("chapterSelect");
   165→
   166→        const uploadInput = document.getElementById("uploadFileInput");
   167→
   168→        const fileInfoBox = document.getElementById("fileInfoBox");
   169→        const fileName = document.getElementById("fileName");
   170→        const fileType = document.getElementById("fileType");
   171→        const fileSize = document.getElementById("fileSize");
   172→
   173→        const previewBox = document.getElementById("previewBox");
   174→        const pdfPreview = document.getElementById("pdfPreview");
   175→        const pdfFrame = document.getElementById("pdfFrame");
   176→
   177→        const textPreview = document.getElementById("textPreview");
   178→        const previewText = document.getElementById("previewText");
   179→
   180→        const unsupportedPreview = document.getElementById("unsupportedPreview");
   181→
   182→        filterChapters();
   183→
   184→        subjectSelect.addEventListener("change", function () {
   185→            chapterSelect.value = "";
   186→            filterChapters();
   187→        });
   188→
   189→        uploadInput.addEventListener("change", async function () {
   190→            const file = this.files[0];
