   193→
   194→            if (!file) {
   195→                return;
   196→            }
   197→
   198→            showFileInfo(file);
   199→
   200→            const extension = getFileExtension(file.name);
   201→
   202→            if (extension === ".pdf") {
   203→                previewPdf(file);
   204→            }
   205→            else if (extension === ".docx") {
   206→                await previewDocx(file);
   207→            }
   208→            else if (extension === ".pptx") {
   209→                await previewPptx(file);
   210→            }
   211→            else {
   212→                showUnsupportedPreview();
   213→            }
   214→        });
   215→
   216→        function filterChapters() {
   217→            const selectedSubjectId = subjectSelect.value;
   218→
   219→            for (const option of chapterSelect.options) {
   220→                if (!option.value) {
   221→                    option.hidden = false;
   222→                    continue;
   223→                }
   224→
   225→                const optionSubjectId = option.getAttribute("data-subject-id");
   226→
   227→                option.hidden = selectedSubjectId
   228→                    && optionSubjectId !== selectedSubjectId;
   229→            }
   230→        }
   231→
   232→        function showFileInfo(file) {
   233→            fileInfoBox.classList.remove("d-none");
   234→
   235→            fileName.textContent = file.name;
   236→            fileType.textContent = file.type || getFileExtension(file.name).toUpperCase();
   237→            fileSize.textContent = formatFileSize(file.size);
   238→        }
   239→
   240→        function previewPdf(file) {
   241→            previewBox.classList.remove("d-none");
   242→            pdfPreview.classList.remove("d-none");
   243→
   244→            const fileUrl = URL.createObjectURL(file);
   245→            pdfFrame.src = fileUrl;
   246→        }
   247→
   248→        async function previewDocx(file) {
   249→            previewBox.classList.remove("d-none");
   250→            textPreview.classList.remove("d-none");
   251→
   252→            try {
   253→                const arrayBuffer = await file.arrayBuffer();
   254→
   255→                const result = await mammoth.extractRawText({
   256→                    arrayBuffer: arrayBuffer
   257→                });
   258→
   259→                const text = result.value?.trim();
   260→
   261→                if (!text) {
   262→                    previewText.textContent = "Không tìm thấy nội dung text trong file DOCX.";
   263→                    return;
   264→                }
   265→
   266→                previewText.textContent = limitPreviewText(text);
   267→            }
   268→            catch (error) {
   269→                previewText.textContent = "Không thể đọc trước nội dung file DOCX.";
   270→            }
   271→        }
   272→
   273→        async function previewPptx(file) {
   274→            previewBox.classList.remove("d-none");
   275→            textPreview.classList.remove("d-none");
   276→
   277→            try {
   278→                const arrayBuffer = await file.arrayBuffer();
   279→                const zip = await JSZip.loadAsync(arrayBuffer);
   280→
   281→                const slideFiles = Object.keys(zip.files)
   282→                    .filter(name => name.startsWith("ppt/slides/slide") && name.endsWith(".xml"))
   283→                    .sort((a, b) => {
   284→                        const numA = parseInt(a.match(/slide(\d+)\.xml/)?.[1] || "0");
   285→                        const numB = parseInt(b.match(/slide(\d+)\.xml/)?.[1] || "0");
   286→                        return numA - numB;
   287→                    });
   288→
   289→                if (slideFiles.length === 0) {
   290→                    previewText.textContent = "Không tìm thấy slide nào trong file PPTX.";
   291→                    return;
   292→                }
   293→
   294→                let allText = "";
   295→
   296→                for (let i = 0; i < slideFiles.length; i++) {
   297→                    const xml = await zip.files[slideFiles[i]].async("text");
   298→
   299→                    const parser = new DOMParser();
   300→                    const xmlDoc = parser.parseFromString(xml, "application/xml");
   301→
   302→                    const textNodes = xmlDoc.getElementsByTagName("a:t");
   303→
   304→                    let slideText = "";
   305→
   306→                    for (let j = 0; j < textNodes.length; j++) {
   307→                        slideText += textNodes[j].textContent + " ";
   308→                    }
   309→
   310→                    if (slideText.trim()) {
   311→                        allText += `Slide ${i + 1}:\n${slideText.trim()}\n\n`;
   312→                    }
   313→                }
   314→
   315→                if (!allText.trim()) {
   316→                    previewText.textContent = "File PPTX không có nội dung text để xem trước.";
   317→                    return;
   318→                }
   319→
   320→                previewText.textContent = limitPreviewText(allText);
   321→            }
   322→            catch (error) {
   323→                previewText.textContent = "Không thể đọc trước nội dung file PPTX.";
   324→            }
   325→        }
   326→
   327→        function showUnsupportedPreview() {
   328→            previewBox.classList.remove("d-none");
   329→            unsupportedPreview.classList.remove("d-none");
   330→        }
   331→
   332→        function resetPreview() {
   333→            fileInfoBox.classList.add("d-none");
   334→            previewBox.classList.add("d-none");
   335→
   336→            pdfPreview.classList.add("d-none");
   337→            textPreview.classList.add("d-none");
   338→            unsupportedPreview.classList.add("d-none");
   339→
   340→            fileName.textContent = "";
   341→            fileType.textContent = "";
   342→            fileSize.textContent = "";
   343→
   344→            pdfFrame.src = "";
   345→            previewText.textContent = "";
   346→        }
   347→
   348→        function getFileExtension(fileName) {
   349→            const lastDotIndex = fileName.lastIndexOf(".");
   350→
   351→            if (lastDotIndex === -1) {
   352→                return "";
   353→            }
   354→
   355→            return fileName
   356→                .substring(lastDotIndex)
   357→                .toLowerCase();
   358→        }
   359→
   360→        function formatFileSize(bytes) {
   361→            if (bytes < 1024) {
   362→                return bytes + " bytes";
   363→            }
   364→
   365→            const kb = bytes / 1024;
   366→
   367→            if (kb < 1024) {
   368→                return kb.toFixed(2) + " KB";
   369→            }
   370→
   371→            const mb = kb / 1024;
   372→
   373→            return mb.toFixed(2) + " MB";
   374→        }
   375→
   376→        function limitPreviewText(text) {
   377→            const maxLength = 8000;
   378→
   379→            if (text.length <= maxLength) {
   380→                return text;
   381→            }
   382→
   383→            return text.substring(0, maxLength)
   384→                + "\n\n... Nội dung xem trước đã được rút gọn.";
   385→        }
