arguments.content:
:root {
  --bg-base: #0d0d0d;
  --bg-surface: #141414;
  --bg-card: #1a1a1a;
  --bg-card-hover: #202020;
  --bg-input: #1e1e1e;
  --bg-input-focus: #242424;
  --border: #2a2a2a;
  --border-light: #333333;
  --text-primary: #e8e8e8;
  --text-secondary: #888888;
  --text-muted: #666666;
  --accent: #4f8ef7;
  --accent-hover: #3a7de0;
  --accent-dim: rgba(79, 142, 247, 0.12);
  --success: #22c55e;
  --warning: #f59e0b;
  --danger: #ef4444;
  --info: #38bdf8;
  --sidebar-width: 240px;
}

html, body {
  background-color: var(--bg-surface) !important;
  color: var(--text-primary) !important;
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  min-height: 100vh;
  margin-bottom: 0 !important;
}

/* ===================== SCROLLBAR ===================== */
::-webkit-scrollbar { width: 6px; height: 6px; }
::-webkit-scrollbar-track { background: var(--bg-base); }
::-webkit-scrollbar-thumb { background: #333; border-radius: 3px; }
::-webkit-scrollbar-thumb:hover { background: #444; }

/* ===================== NAVBAR ===================== */
.navbar {
  background-color: var(--bg-base) !important;
  border-bottom: 1px solid var(--border) !important;
  box-shadow: none !important;
  padding: 0 1.25rem;
  min-height: 56px;
}

.navbar-brand {
  color: var(--text-primary) !important;
  font-weight: 700;
  font-size: 1.1rem;
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.navbar-brand::before {
  content: '🎓';
  font-size: 1.2rem;
}

.navbar-toggler {
  border-color: var(--border) !important;
}

.navbar-toggler-icon {
  filter: invert(1);
}

.nav-link {
  color: var(--text-secondary) !important;
  padding: 0.5rem 0.75rem !important;
  border-radius: 6px;
  transition: color 0.15s, background 0.15s;
  font-size: 0.9rem;
}

.nav-link:hover {
  color: var(--text-primary) !important;
  background-color: var(--bg-card) !important;
}

.nav-link.text-danger {
  color: #f87171 !important;
}

.nav-link.text-primary {
  color: var(--accent) !important;
}

/* ===================== MAIN CONTAINER ===================== */
.container {
  max-width: 1200px;
}

/* ===================== HEADINGS ===================== */
h1, h2, h3, h4, h5, h6 {
  color: var(--text-primary);
}

h2 {
  font-size: 1.4rem;
  font-weight: 600;
  margin-bottom: 1.25rem;
  padding-bottom: 0.75rem;
  border-bottom: 1px solid var(--border);
}

/* ===================== CARDS ===================== */
.card {
  background-color: var(--bg-card) !important;
  border: 1px solid var(--border) !important;
  border-radius: 10px !important;
  box-shadow: none !important;
}

.card-header {
  background-color: rgba(255,255,255,0.03) !important;
  border-bottom: 1px solid var(--border) !important;
  color: var(--text-primary) !important;
  font-weight: 500;
  padding: 0.875rem 1.125rem;
}

.card-body {
  color: var(--text-primary) !important;
  padding: 1.125rem;
}

/* ===================== FORMS ===================== */
.form-control, .form-select {
  background-color: var(--bg-input) !important;
  border: 1px solid var(--border-light) !important;
  color: var(--text-primary) !important;
  border-radius: 8px;
  padding: 0.55rem 0.875rem;
  transition: border-color 0.15s, box-shadow 0.15s;
}

.form-control:focus, .form-select:focus {
  background-color: var(--bg-input-focus) !important;
  border-color: var(--accent) !important;
  box-shadow: 0 0 0 3px rgba(79, 142, 247, 0.15) !important;
  color: var(--text-primary) !important;
}

.form-control::placeholder {
  color: var(--text-muted) !important;
}

.form-label {
  color: var(--text-secondary);
  font-size: 0.875rem;
  font-weight: 500;
  margin-bottom: 0.4rem;
}

.form-select option {
  background-color: var(--bg-card);
  color: var(--text-primary);
}

/* ===================== BUTTONS ===================== */
.btn-primary {
  background-color: var(--accent) !important;
  border-color: var(--accent) !important;
  color: #fff !important;
  border-radius: 8px;
  font-weight: 500;
  transition: background 0.15s, opacity 0.15s;
}

.btn-primary:hover {
  background-color: var(--accent-hover) !important;
  border-color: var(--accent-hover) !important;
}

.btn-secondary {
  background-color: #2a2a2a !important;
  border-color: var(--border-light) !important;
  color: var(--text-secondary) !important;
  border-radius: 8px;
}

.btn-secondary:hover {
  background-color: #333 !important;
  color: var(--text-primary) !important;
}

.btn-success {
  background-color: #16a34a !important;
  border-color: #16a34a !important;
  border-radius: 8px;
}

.btn-success:hover {
  background-color: #15803d !important;
  border-color: #15803d !important;
}

.btn-danger {
  background-color: #dc2626 !important;
  border-color: #dc2626 !important;
  border-radius: 8px;
}

.btn-danger:hover {
  background-color: #b91c1c !important;
}

.btn-warning {
  background-color: #d97706 !important;
  border-color: #d97706 !important;
  color: #fff !important;
  border-radius: 8px;
}

.btn-info {
  background-color: #0284c7 !important;
  border-color: #0284c7 !important;
  color: #fff !important;
  border-radius: 8px;
}

.btn-outline-danger {
  border-color: #dc2626 !important;
  color: #f87171 !important;
  border-radius: 8px;
}

.btn-outline-danger:hover {
  background-color: #dc2626 !important;
  color: #fff !important;
}

/* ===================== ALERTS ===================== */
.alert {
  border-radius: 8px;
  border: 1px solid;
  font-size: 0.9rem;
}

.alert-success {
  background-color: rgba(34, 197, 94, 0.1) !important;
  border-color: rgba(34, 197, 94, 0.25) !important;
  color: #4ade80 !important;
}

.alert-danger {
  background-color: rgba(239, 68, 68, 0.1) !important;
  border-color: rgba(239, 68, 68, 0.25) !important;
  color: #f87171 !important;
}

.alert-warning {
  background-color: rgba(245, 158, 11, 0.1) !important;
  border-color: rgba(245, 158, 11, 0.25) !important;
  color: #fbbf24 !important;
}

.alert-info {
  background-color: rgba(56, 189, 248, 0.1) !important;
  border-color: rgba(56, 189, 248, 0.25) !important;
  color: #7dd3fc !important;
}

/* ===================== TABLES ===================== */
.table {
  color: var(--text-primary) !important;
  border-color: var(--border) !important;
}

.table > :not(caption) > * > * {
  background-color: transparent !important;
  border-bottom-color: var(--border) !important;
  color: var(--text-primary) !important;
  padding: 0.75rem 0.875rem;
}

.table thead th {
  color: var(--text-secondary) !important;
  font-size: 0.8rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  border-bottom: 1px solid var(--border-light) !important;
  background-color: rgba(255,255,255,0.02) !important;
}

.table-bordered td, .table-bordered th {
  border-color: var(--border) !important;
}

.table-striped > tbody > tr:nth-of-type(odd) > * {
  background-color: rgba(255,255,255,0.02) !important;
}

.table tbody tr:hover > * {
  background-color: rgba(255,255,255,0.04) !important;
}

/* ===================== LIST GROUP ===================== */
.list-group-item {
  background-color: var(--bg-card) !important;
  border-color: var(--border) !important;
  color: var(--text-primary) !important;
  padding: 0.75rem 1rem;
  transition: background 0.15s;
}

.list-group-item:hover {
  background-color: var(--bg-card-hover) !important;
}

.list-group-item.active {
  background-color: var(--accent-dim) !important;
  border-color: var(--accent) !important;
  color: var(--accent) !important;
}

/* ===================== BADGES ===================== */
.badge {
  border-radius: 5px;
  font-weight: 500;
  font-size: 0.75rem;
  padding: 0.3em 0.6em;
}

/* ===================== HR / DIVIDER ===================== */
hr {
  border-color: var(--border) !important;
  opacity: 1;
}

/* ===================== TEXT UTILITIES ===================== */
.text-muted {
  color: var(--text-muted) !important;
}

.text-dark {
  color: var(--text-primary) !important;
}

/* ===================== FOOTER ===================== */
.footer {
  background-color: var(--bg-base) !important;
  border-top: 1px solid var(--border) !important;
  color: var(--text-muted) !important;
  font-size: 0.85rem;
  padding: 1rem 0;
  position: static !important;
  margin-top: 3rem;
}

.footer a {
  color: var(--accent) !important;
}

/* ===================== VALIDATION ===================== */
.text-danger {
  color: #f87171 !important;
}

.field-validation-error {
  color: #f87171;
  font-size: 0.8rem;
}

/* ===================== CHAT PAGE ===================== */
.chat-layout {
  display: flex;
  gap: 0;
  min-height: calc(100vh - 120px);
  margin: 0 -12px;
}

.chat-sidebar {
  width: var(--sidebar-width);
  min-width: var(--sidebar-width);
  background-color: var(--bg-base);
  border-right: 1px solid var(--border);
  display: flex;
  flex-direction: column;
  padding: 1rem 0;
  border-radius: 10px 0 0 10px;
  overflow: hidden;
}

.chat-sidebar-header {
  padding: 0 1rem 0.75rem;
  border-bottom: 1px solid var(--border);
  margin-bottom: 0.75rem;
  font-size: 0.8rem;
  font-weight: 600;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.chat-new-btn {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  margin: 0 0.75rem 0.75rem;
  padding: 0.6rem 0.875rem;
  background-color: var(--accent-dim);
  border: 1px solid rgba(79, 142, 247, 0.2);
  border-radius: 8px;
  color: var(--accent) !important;
  text-decoration: none !important;
  font-size: 0.875rem;
  font-weight: 500;
  transition: background 0.15s;
}

.chat-new-btn:hover {
  background-color: rgba(79, 142, 247, 0.2) !important;
}

.chat-session-list {
  flex: 1;
  overflow-y: auto;
  padding: 0 0.5rem;
}

.chat-session-item {
  display: block;
  padding: 0.65rem 0.875rem;
  border-radius: 7px;
  margin-bottom: 2px;
  text-decoration: none !important;
  color: var(--text-secondary) !important;
  font-size: 0.875rem;
  transition: background 0.15s, color 0.15s;
  cursor: pointer;
  position: relative;
}

.chat-session-item:hover {
  background-color: var(--bg-card) !important;
  color: var(--text-primary) !important;
}

.chat-session-item.active {
  background-color: var(--accent-dim) !important;
  color: var(--accent) !important;
}

.chat-session-title {
  display: block;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  font-weight: 500;
  font-size: 0.875rem;
}

.chat-session-meta {
  display: block;
  font-size: 0.75rem;
  color: var(--text-muted);
  margin-top: 2px;
}

.chat-session-delete {
  display: none;
  position: absolute;
  right: 0.5rem;
  top: 50%;
  transform: translateY(-50%);
  background: none;
  border: none;
  color: var(--text-muted);
  padding: 2px 5px;
  border-radius: 4px;
  cursor: pointer;
  font-size: 0.8rem;
  transition: color 0.15s;
}

.chat-session-item:hover .chat-session-delete {
  display: block;
}

.chat-session-delete:hover {
  color: var(--danger) !important;
}

.chat-main {
  flex: 1;
  display: flex;
  flex-direction: column;
  background-color: var(--bg-surface);
  border-radius: 0 10px 10px 0;
  overflow: hidden;
  min-height: 600px;
}

.chat-main-header {
  padding: 1rem 1.5rem;
  border-bottom: 1px solid var(--border);
  display: flex;
  align-items: center;
  gap: 0.75rem;
  background-color: var(--bg-card);
}

.chat-main-header-icon {
  width: 36px;
  height: 36px;
  border-radius: 8px;
  background-color: var(--accent-dim);
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--accent);
  font-size: 1rem;
}

.chat-main-title {
  font-weight: 600;
  font-size: 1rem;
  color: var(--text-primary);
  margin: 0;
}

.chat-main-subtitle {
  font-size: 0.8rem;
  color: var(--text-muted);
}

.chat-subject-bar {
  padding: 0.875rem 1.5rem;
  border-bottom: 1px solid var(--border);
  background-color: rgba(255,255,255,0.01);
  display: flex;
  align-items: center;
  gap: 0.75rem;
}

.chat-subject-bar label {
  font-size: 0.85rem;
  color: var(--text-secondary);
  white-space: nowrap;
  margin: 0;
}

.chat-subject-bar .form-select {
  flex: 1;
  max-width: 320px;
  padding: 0.4rem 0.75rem;
  font-size: 0.875rem;
}

.chat-messages {
  flex: 1;
  overflow-y: auto;
  padding: 1.5rem;
  display: flex;
  flex-direction: column;
  gap: 1.25rem;
}

.chat-empty-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  height: 100%;
  min-height: 280px;
  color: var(--text-muted);
  text-align: center;
}

.chat-empty-icon {
  width: 64px;
  height: 64px;
  border-radius: 16px;
  background-color: var(--bg-card);
