  margin-bottom: 1rem;
}

.chat-empty-title {
  font-size: 1.1rem;
  font-weight: 600;
  color: var(--text-secondary);
  margin-bottom: 0.4rem;
}

.chat-empty-subtitle {
  font-size: 0.85rem;
