  border-radius: 16px 16px 16px 4px;
  padding: 0.875rem 1rem;
  max-width: 80%;
  font-size: 0.9rem;
  line-height: 1.6;
  white-space: pre-wrap;
  word-break: break-word;
}

.chat-message-time {
