            <div class="login-subtitle">Hỏi đáp tài liệu môn học bằng AI</div>
        </div>

        @if (TempData["ErrorMessage"] != null)
        {
            <div class="alert alert-danger mb-3">
                @TempData["ErrorMessage"]
            </div>
        }

        <div asp-validation-summary="All" class="alert alert-danger mb-3" style="display:none;"></div>

        <form method="post">

            <div class="mb-3">
                <label class="form-label">Email</label>
                <input asp-for="Email"
                       type="email"
                       class="form-control"
                       placeholder="example@gmail.com"
                       autocomplete="username" />
                <span asp-validation-for="Email" class="field-validation-error"></span>
            </div>

            <div class="mb-4">
                <label class="form-label">Mật khẩu</label>
                <input asp-for="Password"
                       type="password"
                       class="form-control"
                       placeholder="••••••••"
                       autocomplete="current-password" />
                <span asp-validation-for="Password" class="field-validation-error"></span>
            </div>

            <button type="submit" class="btn btn-primary login-submit">
                Đăng nhập
            </button>

        </form>

        <div class="mt-3 text-center" style="font-size:0.8rem; color: var(--text-muted);">
            Tài khoản demo: student@gmail.com / 123456
        </div>
    </div>
</div>

@section Scripts {
    <script>
        const summary = document.querySelector('[data-valmsg-summary]') || document.querySelector('.validation-summary-errors');
