<div class="chat-layout">

    <div class="chat-sidebar">
        <div class="chat-sidebar-header">Cuộc trò chuyện</div>

        <a asp-page="/Chat/Index" class="chat-new-btn">
            <span>＋</span> Cuộc trò chuyện mới
        </a>

        <div class="chat-session-list">
            @if (Model.Sessions.Count == 0)
            {
                <div style="padding: 0.75rem 1rem; color: var(--text-muted); font-size:0.85rem;">
                    Chưa có cuộc trò chuyện nào.
                </div>
            }
            else
            {
                @foreach (var session in Model.Sessions)
                {
                    var isActive = Model.CurrentSessionId == session.ChatSessionId;
                    <div class="chat-session-item @(isActive ? "active" : "")">
                        <a asp-page="/Chat/Index"
                           asp-route-sessionId="@session.ChatSessionId"
                           style="text-decoration:none; color:inherit; display:block;">
                            <span class="chat-session-title">@session.Title</span>
                            <span class="chat-session-meta">
                                @((session.UpdatedAt ?? session.CreatedAt).ToString("dd/MM HH:mm"))
                            </span>
                        </a>
                        <form method="post"
                              asp-page-handler="Delete"
                              style="display:inline;"
                              onsubmit="return confirm('Xóa cuộc trò chuyện này?');">
                            <input type="hidden" name="chatSessionId" value="@session.ChatSessionId" />
                            <button type="submit" class="chat-session-delete" title="Xóa">✕</button>
                        </form>
                    </div>
                }
            }
        </div>
    </div>

    <div class="chat-main">

        <div class="chat-main-header">
            <div class="chat-main-header-icon">💬</div>
            <div>
                <div class="chat-main-title">
                    @if (Model.CurrentSession != null)
                    {
                        @Model.CurrentSession.Title
                    }
                    else
                    {
                        <text>Cuộc trò chuyện mới</text>
                    }
                </div>
                <div class="chat-main-subtitle">Hỏi đáp dựa trên tài liệu môn học</div>
            </div>
        </div>

        <form method="post" asp-page-handler="Ask" id="chatForm">
            <input type="hidden" asp-for="CurrentSessionId" />

            <div class="chat-subject-bar">
                <label>Môn học:</label>
                <select asp-for="SubjectId" class="form-select">
                    <option value="">Tất cả tài liệu đã được duyệt</option>
                    @foreach (var subject in Model.Subjects)
                    {
                        <option value="@subject.SubjectId">@subject.SubjectName</option>
                    }
                </select>
            </div>

            <div class="chat-messages" id="chatMessages">

                @if (Model.CurrentSession == null || Model.CurrentSession.Messages.Count == 0)
                {
                    <div class="chat-empty-state">
                        <div class="chat-empty-icon">💬</div>
                        <div class="chat-empty-title">Bắt đầu cuộc trò chuyện</div>
                        <div class="chat-empty-subtitle">
                            Chatbot sẽ trả lời dựa trên tài liệu đã được duyệt và index.
                            Hãy chọn môn học để tìm kiếm chính xác hơn.
                        </div>
                    </div>
                }
                else
                {
                    foreach (var message in Model.CurrentSession.Messages)
                    {
                        if (message.Role == "User")
                        {
                            <div class="chat-message-user">
                                <div>
                                    <div class="bubble">@message.Content</div>
                                    <div class="chat-message-time text-end">
                                        @message.CreatedAt.ToString("dd/MM/yyyy HH:mm")
                                    </div>
                                </div>
                            </div>
                        }
                        else
                        {
                            <div class="chat-message-ai">
                                <div class="bubble">@message.Content</div>
                                <div class="chat-message-time">
                                    @message.CreatedAt.ToString("dd/MM/yyyy HH:mm")
                                </div>

                                @if (message.Sources.Count > 0)
                                {
                                    <div class="chat-sources">
                                        <div class="chat-sources-title">📎 Nguồn tài liệu</div>
                                        @foreach (var source in message.Sources)
                                        {
                                            <div class="chat-source-item">
                                                <strong>@source.DocumentName</strong>
                                                &nbsp;·&nbsp; Đoạn #@source.ChunkIndex
                                                &nbsp;·&nbsp; Độ liên quan: @source.SimilarityScore.ToString("F3")

                                                @if (!string.IsNullOrWhiteSpace(source.Excerpt))
                                                {
                                                    <div style="margin-top:0.35rem; color: var(--text-muted); font-size:0.78rem; white-space:pre-wrap;">
                                                        @source.Excerpt
                                                    </div>
                                                }
                                            </div>
                                        }
                                    </div>
                                }
                            </div>
                        }
                    }
                }

            </div>

            <div class="chat-input-area">
                <div class="chat-input-wrapper">
                    <textarea asp-for="Question"
                              id="questionInput"
                              placeholder="Đặt câu hỏi dựa trên tài liệu môn học..."
                              rows="1"></textarea>
                    <button type="submit" class="chat-send-btn" title="Gửi">➤</button>
                </div>
                <div class="chat-disclaimer">
                    Câu trả lời được tạo dựa trên tài liệu giảng viên tải lên. Hãy kiểm tra thông tin quan trọng.
                </div>
            </div>

        </form>
    </div>

</div>

@if (TempData["SuccessMessage"] != null)
{
    <div class="alert alert-success mt-3">@TempData["SuccessMessage"]</div>
}
@if (TempData["ErrorMessage"] != null)
{
    <div class="alert alert-danger mt-3">@TempData["ErrorMessage"]</div>
}

@section Scripts {
<script>
    const chatMessages = document.getElementById('chatMessages');
    if (chatMessages) {
        chatMessages.scrollTop = chatMessages.scrollHeight;
    }

    const textarea = document.getElementById('questionInput');
    if (textarea) {
        textarea.addEventListener('keydown', function (e) {
            if (e.key === 'Enter' && !e.shiftKey) {
                e.preventDefault();
                document.getElementById('chatForm').submit();
            }
        });

        textarea.addEventListener('input', function () {
            this.style.height = 'auto';
            this.style.height = Math.min(this.scrollHeight, 120) + 'px';
        });
    }
</script>
}

@page
@using PRN212_VietnameseEduChat.Services.Security
@using Microsoft.AspNetCore.Html
@model PRN212_VietnameseEduChat.Pages.Documents.IndexModel

@{
    ViewData["Title"] = "Quản lý tài liệu";
}

<div class="page-header">
    <h2>📄 Quản lý tài liệu</h2>
    @if (User.IsInRole(AppRoles.Lecturer) || User.IsInRole(AppRoles.AcademicAdmin))
    {
        <a asp-page="Upload" class="btn btn-primary">
            ⬆️ Tải lên tài liệu
        </a>
    }
</div>

@if (TempData["SuccessMessage"] != null)
{
    <div class="alert alert-success">@TempData["SuccessMessage"]</div>
}
@if (TempData["ErrorMessage"] != null)
{
    <div class="alert alert-danger">@TempData["ErrorMessage"]</div>
}

@if (Model.Documents.Count == 0)
{
    <div class="alert alert-info">
        Không có tài liệu nào để hiển thị.
    </div>
}
else
{
    <div class="card">
        <div class="card-body" style="padding:0; overflow-x:auto;">
            <table class="table table-bordered align-middle mb-0">
                <thead>
                    <tr>
                        <th>Tiêu đề</th>
                        <th>Môn học / Chương</th>
                        <th>Trạng thái</th>
                        <th>Chunks</th>
                        <th>Ngày tải</th>
                        <th>Người tải</th>
                        <th>Người duyệt</th>
                        <th style="width: 200px;">Thao tác</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var item in Model.Documents)
                    {
                        <tr>
                            <td>
                                <strong>@item.Title</strong>
                                <div style="font-size:0.8rem; color:var(--text-muted);">@item.OriginalFileName</div>
                                @if (!string.IsNullOrWhiteSpace(item.ErrorMessage))
                                {
                                    <div class="text-danger" style="font-size:0.78rem;">@item.ErrorMessage</div>
                                }
                                @if (!string.IsNullOrWhiteSpace(item.RejectionReason))
                                {
                                    <div style="color:#fbbf24; font-size:0.78rem;">Từ chối: @item.RejectionReason</div>
                                }
                            </td>
                            <td>
                                <div>@(item.Subject?.SubjectName ?? "Chưa phân loại")</div>
                                <div style="font-size:0.8rem; color:var(--text-muted);">@(item.Chapter?.ChapterName ?? "")</div>
                            </td>
                            <td>@RenderStatus(item.Status)</td>
                            <td>@item.TotalChunks</td>
                            <td style="font-size:0.85rem;">@item.UploadedAt.ToString("dd/MM/yy HH:mm")</td>
                            <td style="font-size:0.85rem;">@(item.User?.FullName ?? "Không rõ")</td>
                            <td style="font-size:0.85rem;">
                                @if (item.Reviewer != null)
                                {
                                    <div>@item.Reviewer.FullName</div>
                                    @if (item.ReviewedAt != null)
                                    {
                                        <div style="color:var(--text-muted); font-size:0.78rem;">@item.ReviewedAt.Value.ToString("dd/MM/yy")</div>
                                    }
                                }
                                else
                                {
                                    <span style="color:var(--text-muted);">—</span>
                                }
                            </td>
                            <td>
                                <div class="d-flex flex-wrap gap-1">
                                    <a asp-page="Details"
                                       asp-route-id="@item.DocumentId"
                                       class="btn btn-sm btn-info">Xem</a>

                                    <a asp-page-handler="Download"
                                       asp-route-id="@item.DocumentId"
                                       class="btn btn-sm btn-success">Tải</a>

                                    @if (User.IsInRole(AppRoles.AcademicAdmin) && item.Status == "PendingApproval")
                                    {
                                        <form method="post" asp-page-handler="Approve" asp-route-id="@item.DocumentId" class="d-inline">
                                            <button type="submit" class="btn btn-sm btn-primary">Duyệt</button>
                                        </form>
                                    }

                                    @if (User.IsInRole(AppRoles.AcademicAdmin) && item.Status != "PendingApproval")
                                    {
                                        <form method="post" asp-page-handler="Delete" asp-route-id="@item.DocumentId" class="d-inline"
                                              onsubmit="return confirm('Xóa tài liệu này?');">
                                            <button type="submit" class="btn btn-sm btn-danger">Xóa</button>
                                        </form>
                                    }
                                </div>

                                @if (User.IsInRole(AppRoles.AcademicAdmin) && item.Status == "PendingApproval")
                                {
                                    <form method="post" asp-page-handler="Reject" asp-route-id="@item.DocumentId" class="mt-2">
                                        <div class="d-flex gap-1">
                                            <input type="text" name="reason" class="form-control form-control-sm" placeholder="Lý do từ chối" />
                                            <button type="submit" class="btn btn-sm btn-warning">Từ chối</button>
                                        </div>
                                    </form>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    </div>
}

@functions {
    private IHtmlContent RenderStatus(string status)
    {
        return status switch
        {
            "Processing" => new HtmlString("<span class=\"badge bg-warning text-dark\">Đang xử lý</span>"),
            "PendingApproval" => new HtmlString("<span class=\"badge bg-secondary\">Chờ duyệt</span>"),
            "Approved" => new HtmlString("<span class=\"badge bg-success\">Đã duyệt</span>"),
            "Rejected" => new HtmlString("<span class=\"badge bg-danger\">Đã từ chối</span>"),
            "Failed" => new HtmlString("<span class=\"badge bg-danger\">Thất bại</span>"),
            _ => new HtmlString($"<span class=\"badge bg-secondary\">{status}</span>")
        };
    }
}

