                        <tr>
                            <td style="color:var(--text-muted); font-size:0.85rem; border:none; padding:0.5rem 0;">Môn học</td>
                            <td style="border:none; padding:0.5rem 0;">@(document.Subject?.SubjectName ?? "Chưa phân loại")</td>
                        </tr>
                        <tr>
                            <td style="color:var(--text-muted); font-size:0.85rem; border:none; padding:0.5rem 0;">Chương</td>
                            <td style="border:none; padding:0.5rem 0;">@(document.Chapter?.ChapterName ?? "Chưa phân loại")</td>
                        </tr>
                        <tr>
                            <td style="color:var(--text-muted); font-size:0.85rem; border:none; padding:0.5rem 0;">Loại file</td>
                            <td style="border:none; padding:0.5rem 0;">@document.ContentType</td>
                        </tr>
                        <tr>
                            <td style="color:var(--text-muted); font-size:0.85rem; border:none; padding:0.5rem 0;">Dung lượng</td>
