                            <td style="color:var(--text-muted); font-size:0.85rem; border:none; padding:0.5rem 0;">Người upload</td>
                            <td style="border:none; padding:0.5rem 0;">@(document.User?.FullName ?? document.User?.Email ?? "Không rõ")</td>
                        </tr>
                        <tr>
                            <td style="color:var(--text-muted); font-size:0.85rem; border:none; padding:0.5rem 0;">Ngày upload</td>
                            <td style="border:none; padding:0.5rem 0;">@document.UploadedAt.ToString("dd/MM/yyyy HH:mm")</td>
                        </tr>
                        <tr>
                            <td style="color:var(--text-muted); font-size:0.85rem; border:none; padding:0.5rem 0;">Trạng thái</td>
                            <td style="border:none; padding:0.5rem 0;">
                                @if (document.Status == "Approved") { <span class="badge bg-success">Đã duyệt</span> }
                                else if (document.Status == "Processing") { <span class="badge bg-warning text-dark">Đang xử lý</span> }
                                else if (document.Status == "PendingApproval") { <span class="badge bg-secondary">Chờ duyệt</span> }
                                else if (document.Status == "Rejected") { <span class="badge bg-danger">Đã từ chối</span> }
                                else if (document.Status == "Failed") { <span class="badge bg-danger">Thất bại</span> }
                                else { <span class="badge bg-secondary">@document.Status</span> }
                            </td>
                        </tr>
                        <tr>
                            <td style="color:var(--text-muted); font-size:0.85rem; border:none; padding:0.5rem 0;">Tổng chunks</td>
                            <td style="border:none; padding:0.5rem 0;">@document.TotalChunks</td>
                        </tr>
                    </tbody>
                </table>

                @if (!string.IsNullOrWhiteSpace(document.ErrorMessage))
                {
                    <div class="alert alert-danger mt-2">
                        <strong>Lỗi xử lý:</strong> @document.ErrorMessage
                    </div>
                }
            </div>
        </div>

        <div class="card mt-3">
            <div class="card-header">Kết quả xử lý AI</div>
            <div class="card-body">
                @if (document.Status == "PendingApproval")
                {
                    <div class="alert alert-info mb-0">
                        Tài liệu đã được trích xuất, chia thành <strong>@document.TotalChunks</strong> đoạn và tạo embedding thành công. Đang chờ duyệt.
                    </div>
                }
                else if (document.Status == "Approved")
                {
                    <div class="alert alert-success mb-0">Tài liệu đã được duyệt và hiển thị cho sinh viên.</div>
                }
                else if (document.Status == "Rejected")
                {
                    <div class="alert alert-warning mb-0">
                        Tài liệu đã bị từ chối.
                        @if (!string.IsNullOrWhiteSpace(document.RejectionReason))
                        {
                            <div class="mt-2"><strong>Lý do:</strong> @document.RejectionReason</div>
                        }
                    </div>
                }
                else if (document.Status == "Failed")
                {
                    <div class="alert alert-danger mb-0">Tài liệu đã tải lên nhưng xử lý nội dung thất bại.</div>
                }
            </div>
        </div>
    </div>

    @if (document.ContentType == "application/pdf")
    {
        <div class="col-md-7">
            <div class="card">
                <div class="card-header">Xem file PDF</div>
                <div class="card-body" style="padding:0; border-radius:0 0 10px 10px; overflow:hidden;">
                    <iframe src="@Url.Page("Details", "Preview", new { id = document.DocumentId })"
                            style="width: 100%; height: 620px; border: none;"></iframe>
                </div>
            </div>
        </div>
    }
</div>

@functions {
    private string FormatFileSize(long bytes)
    {
        if (bytes < 1024) return bytes + " bytes";
        var kb = bytes / 1024.0;
        if (kb < 1024) return kb.ToString("0.00") + " KB";
        return (kb / 1024.0).ToString("0.00") + " MB";
    }
}

